/** Mapa id → lição para lookups rápidos */
export const licoesPorId = Object.fromEntries(licoes.map(l => [l.id, l]))

/** Lições agrupadas por cicloId */
export const licoesPorCiclo = licoes.reduce((acc, l) => {
  if (!acc[l.cicloId]) acc[l.cicloId] = []
  acc[l.cicloId].push(l)
  return acc
}, {})
